public TransDate parmTransDate()
{
    TransDate       retDate = next parmTransDate();

    if(fetchInventAgingReceiptView && inventTable.isItemBatchActivated())
    {
        InventAgingReceiptView  recptView;
        //TransDate batchDate = InventBatch::find(inventDim.InventBatchId, inventTable.ItemId).prodDate;
        select firstonly1 recptView order by recptView.TransDate
            where recptView.ItemId      ==  inventTable.ItemId
            &&  recptView.inventBatchId ==  inventDim.InventBatchId;
        TransDate batchDate = recptView.TransDate;
        retDate =  batchDate != dateNull() ? batchDate : retDate;
    }

    return retDate;
}
